      mr: "6 \u092E\u0939\u093F\u0928\u094D\u092F\u093E\u0902\u0924 \u0918\u0928 \u0906\u0939\u093E\u0930 \u0938\u0941\u0930\u0942 \u0915\u0930\u0923\u0947"
