        "\u090F\u0915\u093E \u0935\u0947\u0933\u0940 \u090F\u0915 \u0905\u0928\u094D\u0928 \u0938\u093E\u0926\u0930 \u0915\u0930\u093E",
        "\u0918\u0928 \u0906\u0939\u093E\u0930\u093E\u0938\u094B\u092C\u0924 \u0938\u094D\u0924\u0928\u092A\u093E\u0928 \u0938\u0941\u0930\u0942 \u0920\u0947\u0935\u093E",
        "\u092C\u093E\u0933\u093E\u0932\u093E \u092A\u094B\u0924 \u0936\u094B\u0927\u0942 \u0926\u094D\u092F\u093E"
