// src/lib/mcp/tools/list-topics.ts
var list_topics_default = defineTool({
  name: "list_topics",
  title: "List topics",
  description: "List all child nutrition and baby care topics available in Info Child, with id, category, and short summary. Use this to discover topics before calling get_topic.",
  inputSchema: {
    language: z.enum(["en", "hi", "mr"]).optional().describe("Language for titles/summaries. Defaults to en."),
    category: z.enum(["breastfeeding", "complementary", "hygiene", "nutrition", "growth"]).optional().describe("Optional category filter.")
  },
  annotations: { readOnlyHint: true, idempotentHint: true, openWorldHint: false },
  handler: ({ language, category }) => {
    const lang = language ?? "en";
    const filtered = category ? topics.filter((t) => t.category === category) : topics;
    const items = filtered.map((t) => ({
      id: t.id,
      category: t.category,
      emoji: t.emoji,
      title: t.title[lang],
      summary: t.summary[lang]
    }));
    return {
      content: [{ type: "text", text: JSON.stringify(items, null, 2) }],
      structuredContent: { topics: items, count: items.length }
    };
  }
});

// src/lib/mcp/tools/get-topic.ts
import { defineTool as defineTool2 } from "npm:@lovable.dev/mcp-js@0.23.0";
import { z as z2 } from "npm:zod@^4.4.3";
var get_topic_default = defineTool2({
  name: "get_topic",
  title: "Get topic detail",
  description: "Get the full detail of a single topic: description, do's, don'ts, and FAQs. Call list_topics first to discover valid ids.",
  inputSchema: {
    id: z2.string().min(1).describe("Topic id (e.g. 'breastfeeding-basics')."),
    language: z2.enum(["en", "hi", "mr"]).optional().describe("Language. Defaults to en.")
  },
  annotations: { readOnlyHint: true, idempotentHint: true, openWorldHint: false },
  handler: ({ id, language }) => {
    const lang = language ?? "en";
    const topic = topics.find((t) => t.id === id);
    if (!topic) {
      return {
        content: [{ type: "text", text: `Topic '${id}' not found.` }],
        isError: true
      };
    }
    const detail = {
      id: topic.id,
      category: topic.category,
      emoji: topic.emoji,
      title: topic.title[lang],
      summary: topic.summary[lang],
      description: topic.description[lang],
      dos: topic.dos[lang],
      donts: topic.donts[lang],
      faqs: topic.faqs.map((f) => ({
        question: f.question[lang],
        answer: f.answer[lang]
      }))
    };
    return {
      content: [{ type: "text", text: JSON.stringify(detail, null, 2) }],
      structuredContent: detail
    };
  }
});

