      mr: "\u0924\u094D\u0935\u091A\u093E \u0938\u0942\u0930\u094D\u092F\u092A\u094D\u0930\u0915\u093E\u0936\u093E\u0924 \u0906\u0932\u094D\u092F\u093E\u0935\u0930 \u0915\u094B\u0923\u0924\u0947 \u0935\u094D\u0939\u093F\u091F\u0945\u092E\u093F\u0928 \u0924\u092F\u093E\u0930 \u0939\u094B\u0924\u0947?"
