// src/lib/mcp/tools/list-tips.ts
var list_tips_default = defineTool5({
  name: "list_tips",
  title: "List daily tips",
  description: "Get daily nutrition and baby care tips as simple, easy-to-read cards. Each tip has an emoji, title, content, and category.",
  inputSchema: {
    language: z5.enum(["en", "hi", "mr"]).optional().describe("Language. Defaults to en."),
    category: z5.enum(["nutrition", "care", "feeding", "hygiene"]).optional().describe("Optional category filter.")
  },
  annotations: { readOnlyHint: true, idempotentHint: true, openWorldHint: false },
  handler: ({ language, category }) => {
    const lang = language ?? "en";
    const filtered = category ? tips.filter((t) => t.category === category) : tips;
    const items = filtered.map((t) => ({
      id: t.id,
      emoji: t.emoji,
      category: t.category,
      title: t.title[lang],
      content: t.content[lang]
    }));
    return {
      content: [{ type: "text", text: JSON.stringify(items, null, 2) }],
      structuredContent: { tips: items, count: items.length }
    };
  }
});

// src/lib/mcp/index.ts
var mcp_default = defineMcp({
  name: "info-child-mcp",
  title: "Info Child MCP",
  version: "0.1.0",
  instructions: "Info Child provides scientific, evidence-based child nutrition and baby care guidance for mothers, pregnant women, and caregivers in India, based on BPNI Maharashtra guidance supported by UNICEF. Available in English (en), Hindi (hi), and Marathi (mr). Use list_topics to discover topics, then get_topic for full detail. Use get_vaccination_schedule for the month-wise infant immunization schedule. Use get_quiz_questions for MCQ-style educational questions. Use list_tips for short daily tips.",
  tools: [
    list_topics_default,
    get_topic_default,
    get_vaccination_schedule_default,
    get_quiz_questions_default,
    list_tips_default
  ]
});

